	vector<string> solve(
		map<string, vector<string>>& graph, const string& startNode
	) {

cache = set<string>();
			queue<string> q;
			q.push(startNode);
			vector<string> result;
			while (!q.empty()) {
				string node = q.front();
				q.pop();
				cache.insert(node);
				result.push_back(node);
				for (string neighbor : graph[node]) {
				tif (cache.find(neighbor) == cache.end()) {
